const b = $node["WH Simpan Opname"].json.body || $node["WH Simpan Opname"].json;
const items = b.items || [];
const opnameid = $input.item.json.id;
return items.map(i => ({ json: { 
  opnameid,
  instansi_id: b.instansi_id || $input.item.json.query?.instansi_id || 'bapperida',
  barangid: i.id, 
  stokfisik: parseInt(i.stok_fisik) || 0, 
  stoksistem: parseInt(i.stok_sistem) || 0,
  selisih: (parseInt(i.stok_fisik) || 0) - (parseInt(i.stok_sistem) || 0)
} }));
